import React, { useState, useEffect } from 'react';
import { useApp } from '../../App';
import { Sidebar } from '../../components/Sidebar';
import LiveMap from '../../components/LiveMap';

// Firebase Engine Integrations
import { db } from '../../utils/firebase';
import { doc, getDoc, collection, onSnapshot } from 'firebase/firestore';

export default function CleanerPortal() {
  const { complaints, updateComplaint } = useApp();

  // Authentication Lock-States
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [parentVendorId, setParentVendorId] = useState('');
  const [cleanerLoginId, setCleanerLoginId] = useState('');
  const [cleanerPassword, setCleanerPassword] = useState('');
  const [activeCleanerData, setActiveCleanerData] = useState(null);

  // Workflow Functional States
  const [selected, setSelected] = useState(null);
  const [proofUrl, setProofUrl] = useState('');

  // Sahi filter telemetry: Sirf wahi tasks jo is cleaner ke naam par assigned hain 
  // Aur abhi tak vendor ne archive (COMPLETED) nahi kiye hain.
  const activeTasks = complaints.filter(c => 
    c.assignedTo === activeCleanerData?.name && 
    ['ASSIGNED_TO_CLEANER', 'CLEANED_BY_FORCE'].includes(c.status)
  );

  // ── AUTH OPERATION: VENDOR SUB-COLLECTION SE VERIFICATION ──
  const handleCleanerLoginAuth = async (e) => {
    e.preventDefault();
    if (!parentVendorId.trim() || !cleanerLoginId.trim() || !cleanerPassword) {
      return alert("Please fill all configuration parameters.");
    }

    try {
      // 1. Check if parent vendor node registry exists
      const venRef = doc(db, "vendors", parentVendorId.trim());
      const venSnap = await getDoc(venRef);
      if (!venSnap.exists()) {
        return alert("Parent Vendor ID not found in system database.");
      }

      // 2. Fetch realtime matrix from vendor's sub-collection
      const unsub = onSnapshot(collection(db, "vendors", parentVendorId.trim(), "cleaners"), (snap) => {
        const found = snap.docs
          .map(d => d.data())
          .find(c => c.phone === cleanerLoginId.trim() && c.password === cleanerPassword);

        if (found) {
          setActiveCleanerData(found);
          setIsAuthenticated(true);
        } else {
          alert("Invalid Cleaner Credentials. Check Phone/Password assigned by Vendor.");
        }
        unsub(); // Clean immediately
      });
    } catch (err) {
      alert("Error establishing secure authentication handshakes.");
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setActiveCleanerData(null);
    setCleanerLoginId('');
    setCleanerPassword('');
    setSelected(null);
  };

  // ── WORKFLOW OPERATION: PROOF SEND TO VENDOR PANEL ──
  const handleSendProofToVendor = async (taskId) => {
    if (!proofUrl.trim()) {
      return alert("Please paste the valid clean site proof image URL.");
    }

    // Database state update trigger loop
    await updateComplaint(taskId, {
      status: 'CLEANED_BY_FORCE',
      cleanerStatus: 'DONE',
      cleanerPhoto: proofUrl.trim()
    });

    alert("Clean image uploaded! Task sent to Vendor verification cluster.");
    setProofUrl('');
    setSelected(null);
  };

  /* ── INTERFACE GATEWAY 1: SECURITY SECURE LOGIN SCREEN ── */
  if (!isAuthenticated) {
    return (
      <div style={{ display: 'flex', minHeight: '100vh', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', background: '#0F172A', fontFamily: 'system-ui, sans-serif' }}>
        <div style={{ background: '#fff', padding: '34px 28px', borderRadius: 16, width: 340, boxShadow: '0 12px 40px rgba(0,0,0,0.3)' }}>
          
          <div style={{ textAlign: 'center', marginBottom: 22 }}>
            <div style={{ fontSize: 24, marginBottom: 6 }}>🧹</div>
            <div style={{ fontSize: 18, fontWeight: 800, color: '#1E293B' }}>Field Cleaner Portal</div>
            <div style={{ fontSize: 11, color: '#64748B', fontWeight: 600, textTransform: 'uppercase', letterSpacing: 0.5, marginTop: 4 }}>GRWMS Ground Enforcement</div>
          </div>

          <form onSubmit={handleCleanerLoginAuth}>
            <div style={{ marginBottom: 14 }}>
              <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#475569', marginBottom: 5 }}>PARENT VENDOR STATION ID</label>
              <input type="text" value={parentVendorId} onChange={e => setParentVendorId(e.target.value)} placeholder="e.g. platform_no_1" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #CBD5E1', boxSizing: 'border-box', fontSize: 13 }} required />
            </div>

            <div style={{ marginBottom: 14 }}>
              <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#475569', marginBottom: 5 }}>CLEANER LOGIN ID (PHONE)</label>
              <input type="text" value={cleanerLoginId} onChange={e => setCleanerLoginId(e.target.value)} placeholder="e.g. 9876543210" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #CBD5E1', boxSizing: 'border-box', fontSize: 13 }} required />
            </div>

            <div style={{ marginBottom: 20 }}>
              <label style={{ display: 'block', fontSize: 11, fontWeight: 700, color: '#475569', marginBottom: 5 }}>APP ACCESS PASSWORD</label>
              <input type="password" value={cleanerPassword} onChange={e => setCleanerPassword(e.target.value)} placeholder="••••••••" style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1px solid #CBD5E1', boxSizing: 'border-box', fontSize: 13 }} required />
            </div>

            <button type="submit" style={{ width: '100%', padding: 12, background: '#10B981', color: '#fff', border: 'none', borderRadius: 8, fontWeight: 700, fontSize: 13, cursor: 'pointer', transition: 'background 0.2s' }}>
              Sign In & Sync Tasks
            </button>
          </form>

        </div>
      </div>
    );
  }

  /* ── INTERFACE GATEWAY 2: LIVE DUTY WORKSPACE PANEL (POST-AUTH) ── */
  return (
    <div style={{ display: 'flex', height: '100vh', background: '#F7F9FC', overflow: 'hidden', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* Sidebar Profile Cluster */}
      <Sidebar 
        title="Field Force Ledger" 
        subtitle={`Staff: ${activeCleanerData?.name}`} 
        navItems={[{ key: 'JOBS', label: 'My Active Duties', icon: '🧹', count: activeTasks.length }]} 
        activeTab="JOBS" 
        onTabChange={() => {}} 
      />

      {/* Main Core Viewport */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        
        {/* Top Floating Control Navbar Bar */}
        <div style={{ background: '#fff', borderBottom: '1px solid #E2E8F0', padding: '12px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <span style={{ fontSize: 12, color: '#64748B' }}>Authenticated Station Node: </span>
            <strong style={{ fontSize: 12, color: '#0F172A' }}>{parentVendorId}</strong>
          </div>
          <button onClick={handleLogout} style={{ background: '#ECEFF1', border: 'none', padding: '6px 12px', borderRadius: 6, cursor: 'pointer', fontSize: 11, fontWeight: 700, color: '#374151' }}>
            Exit Session (Logout)
          </button>
        </div>

        {/* Dynamic Split Screen Body */}
        <div style={{ flex: 1, display: 'flex', padding: 20, gap: 16, overflow: 'hidden' }}>
          
          {/* LEFT SUB-COLUMN: ACTIVE ASSIGNED RUNNING TICKETS */}
          <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 10 }}>
            <h3 style={{ fontSize: 15, color: '#0A1628', margin: '0 0 4px 0', fontWeight: 800 }}>📌 My Assigned Sweeps</h3>
            
            {activeTasks.length === 0 ? (
              <div style={{ background: '#fff', padding: 30, borderRadius: 12, border: '1px solid #DDE3E9', textAlign: 'center', color: '#7A8FA6', fontSize: 13 }}>
                Sab Saaf Hai! No active tracking tasks allocated to you.
              </div>
            ) : (
              activeTasks.map(t => {
                const isUnderReview = t.status === 'CLEANED_BY_FORCE';
                return (
                  <div 
                    key={t.id} 
                    onClick={() => setSelected(t)} 
                    style={{ 
                      background: isUnderReview ? '#FFF9E6' : '#fff', 
                      padding: 14, 
                      borderRadius: 12, 
                      border: `1px solid ${selected?.id === t.id ? '#1565C0' : isUnderReview ? '#FFE0B2' : '#DDE3E9'}`, 
                      cursor: 'pointer',
                      boxShadow: '0 2px 5px rgba(0,0,0,0.01)',
                      transition: 'all 0.15s'
                    }}
                  >
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <div style={{ fontWeight: 700, fontSize: 13, color: '#0F172A' }}>
                        📍 {t.area || 'Platform Sub-Section'}
                      </div>
                      {isUnderReview && (
                        <span style={{ background: '#E65100', color: '#fff', fontSize: 9, padding: '2px 6px', borderRadius: 4, fontWeight: 700 }}>
                          Under Review
                        </span>
                      )}
                    </div>
                    <div style={{ fontSize: 11, color: '#7A8FA6', marginTop: 5 }}>
                      Ref Code: <strong>{t.customTicketId || t.id?.substring(0, 6)}</strong> | Type: {t.title || t.gtype}
                    </div>
                  </div>
                );
              })
            )}
          </div>

          {/* RIGHT SUB-COLUMN: INTERACTIVE TELEMETRY OVERLAY & RESOLUTION FORM */}
          <div style={{ flex: 1, background: '#fff', borderRadius: 14, border: '1px solid #DDE3E9', padding: 18, display: 'flex', flexDirection: 'column', gap: 14, overflowY: 'auto' }}>
            {selected ? (
              <>
                <div>
                  <h4 style={{ margin: '0 0 2px 0', fontSize: 15, color: '#0A1628' }}>Location Telemetry Map</h4>
                  <span style={{ fontSize: 11, color: '#7A8FA6' }}>Follow target GPS deployment nodes</span>
                </div>

                {/* Map Rendering Bridge */}
                <LiveMap singlePin={true} singleCoords={{ lat: selected.lat, lng: selected.lng }} height="150px" />
                
                {/* External Routing Engine Link */}
                {selected.lat && selected.lng && (
                  <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: '#F1F5F9', padding: '8px 10px', borderRadius: 6 }}>
                    <span style={{ fontSize: 10, fontFamily: 'monospace', color: '#475569' }}>
                      GPS Matrix: {selected.lat.toFixed(5)}, {selected.lng.toFixed(5)}
                    </span>
                    <a 
                      href={`https://www.google.com/maps/search/?api=1&query=${selected.lat},${selected.lng}`} 
                      target="_blank" 
                      rel="noreferrer" 
                      style={{ background: '#1565C0', color: '#fff', padding: '5px 10px', borderRadius: 5, fontSize: 11, fontWeight: 700, textDecoration: 'none' }}
                    >
                      🗺️ Open Directions
                    </a>
                  </div>
                )}

                {/* Citizens Original Image Container */}
                <div>
                  <span style={{ fontSize: 11, fontWeight: 700, color: '#EF4444', display: 'block', marginBottom: 5 }}>
                    ⚠️ CITIZEN IMAGE REPORT (BEFORE CLEANUP):
                  </span>
                  {(selected.imageUrl || selected.image) ? (
                    <img 
                      src={selected.imageUrl || selected.image} 
                      alt="Garbage Proof Trace" 
                      style={{ width: '100%', height: 130, objectFit: 'cover', borderRadius: 10, border: '1px solid #FCA5A5' }} 
                    />
                  ) : (
                    <div style={{ background: '#F8FAFC', padding: 10, borderRadius: 6, fontSize: 11, color: '#64748B', fontStyle: 'italic', textAlign: 'center' }}>
                      No visual media uploaded by source reporter.
                    </div>
                  )}
                </div>

                {/* Real-time Task Pipeline State Actions */}
                <div style={{ marginTop: 'auto', borderTop: '1px solid #E2E8F0', paddingTop: 12 }}>
                  {selected.status === 'ASSIGNED_TO_CLEANER' ? (
                    <div style={{ background: '#F8FAFC', padding: 12, borderRadius: 10, border: '1px solid #E2E8F0' }}>
                      <label style={{ fontSize: 11, fontWeight: 700, color: '#0F172A', display: 'block', marginBottom: 6 }}>
                        📸 UPLOAD CLEAN PLACE EVIDENCE (PASTE PHOTO URL):
                      </label>
                      <input 
                        type="text" 
                        placeholder="Paste clean spot picture URL here..." 
                        value={proofUrl} 
                        onChange={e => setProofUrl(e.target.value)} 
                        style={{ width: '100%', padding: '10px', fontSize: 12, borderRadius: 6, border: '1px solid #CBD5E1', boxSizing: 'border-box', marginBottom: 10 }} 
                      />
                      <button 
                        onClick={() => handleSendProofToVendor(selected.id)} 
                        style={{ width: '100%', background: '#10B981', color: '#fff', padding: 12, border: 'none', borderRadius: 8, fontWeight: 700, cursor: 'pointer', fontSize: 12 }}
                      >
                        Submit Proof & Notify Vendor
                      </button>
                    </div>
                  ) : (
                    <div style={{ background: '#FFF3E0', border: '1px solid #FFE0B2', borderRadius: 10, padding: 12, textAlign: 'center' }}>
                      <div style={{ fontSize: 12, fontWeight: 700, color: '#E65100', marginBottom: 3 }}>
                        ⏳ Verification Pipeline Active
                      </div>
                      <div style={{ fontSize: 11, color: '#64748B' }}>
                        Clean image sent to Vendor. The ticket will automatically clear once the vendor audits both 'Before' and 'After' assets and clicks 'Verify & Close'.
                      </div>
                    </div>
                  )}
                </div>
              </>
            ) : (
              <div style={{ margin: 'auto', color: '#7A8FA6', fontSize: 12, textAlign: 'center' }}>
                Select an allocated duty tracking ticket card from the left grid panel to manage location analytics.
              </div>
            )}
          </div>

        </div>
      </div>
    </div>
  );
}
